#include<bits/stdc++.h>
using namespace std;

struct Student {
    string full_name;  // Changed to string to store names
    int grade_score;   // Renamed for consistency and convention
};  // Added missing semicolon

Student students[1001];  // Fixed struct name capitalization

int max_grade_score;
string max_grade_student_name;  // Changed to store name directly
int total_students;

int main() {
    cin >> total_students;

    for (int i = 0; i < total_students; i++) {  // Changed to 0-based index
        cin >> students[i].grade_score >> students[i].full_name;
    }

    // Initialize with first student's data
    max_grade_score = students[0].grade_score;
    max_grade_student_name = students[0].full_name;

    for (int i = 1; i < total_students; i++) {
        if (max_grade_score < students[i].grade_score) {
            max_grade_score = students[i].grade_score;
            max_grade_student_name = students[i].full_name;
        }
    }

    cout << max_grade_student_name;  // Output the name instead of index
    return 0;
}
